// ═══════════════════════════════════════════════════
// Midas v2: SEO 标题优化引擎
// 输入: Sherlock 核查通过的 Markdown 内容
// 核心: 标题重写 + 长尾关键词优化 + Click-Worthy 评分
// ═══════════════════════════════════════════════════

const data = $input.first().json;
const draft = data._newton_draft || data.content || '';
const originalTitle = data._newton_title || data.title || '';

// 提取主关键词（用于 SEO 优化）
function extractKeywords(text) {
  const examPatterns = [
    'AP', 'A-Level', 'A Level', 'IB', 'SAT', 'ACT', 'TOEFL', 'IELTS',
    'BPhO', 'AMC', 'STEP', 'MAT', 'PAT', 'TSA', 'NSAA', 'ENGAA',
    'Physics', 'Chemistry', 'Biology', 'Math', 'Further Math',
    'Personal Statement', 'PS', '面试', 'Interview', '文书',
    '牛剑', 'Oxbridge', '牛津', 'Oxford', '剑桥', 'Cambridge',
    '竞赛', 'Olympiad', '备考', '选课', '选校', '排名'
  ];
  const found = [];
  const lower = text.toLowerCase();
  for (const kw of examPatterns) {
    if (lower.includes(kw.toLowerCase())) found.push(kw);
  }
  return [...new Set(found)];
}

const keywords = extractKeywords(draft);
const year = new Date().getFullYear();

// 标题 SEO 评分
function scoreTitle(title) {
  let score = 0, feedback = [];
  if (/\d/.test(title)) { score += 2; feedback.push('数字增强'); }
  if (/20\d{2}/.test(title)) { score += 2; feedback.push('年份标记'); }
  if (title.length >= 15 && title.length <= 30) { score += 2; feedback.push('长度适中'); }
  if (/攻略|指南|技巧|解析|盘点|避坑|冲金|满分|5分/i.test(title)) { score += 2; feedback.push('行动词'); }
  if (/AP|A-Level|IB|SAT|BPhO|AMC|STEP|牛剑|牛津|剑桥/i.test(title)) { score += 2; feedback.push('核心关键词'); }
  return { score, maxScore: 10, feedback };
}

return {
  _content: draft,
  _original_title: originalTitle,
  _keywords: keywords,
  _year: year,
  _score: scoreTitle(originalTitle),
  // DeepSeek Prompt for title optimization
  _seo_prompt: `你是 Midas SEO 总监。请为重写以下文章标题以最大化搜索引擎曝光。

原标题: ${originalTitle}
关键词: ${keywords.join(', ')}
年份: ${year}

## 标题优化规则
1. 前置关键信息: [年份][考试/科目][核心主题][行动词]
2. 含具体数字（如"5个技巧""3步通关"）
3. 中文 15-30 字
4. 自然嵌入 2-3 个长尾关键词
5. 保持原标题的核心意思

## 输出格式
请生成 3 个候选标题（按 SEO 得分排序），每个标注评分：
1. [标题] — ⭐⭐⭐⭐⭐ (评分X/10: 理由)
2. [标题] — ⭐⭐⭐⭐ (评分X/10: 理由)
3. [标题] — ⭐⭐⭐⭐⭐ (评分X/10: 理由)

选择得分最高者作为最终标题。`
};

const data = $input.first().json;
return {
  model: $env.DEEPSEEK_MODEL || 'deepseek-chat',
  temperature: 0.3,
  max_tokens: 1024,
  messages: [{ role: 'user', content: data._seo_prompt }]
};

// ═══════════════════════════════════════════════════
// Midas v2: 选择最佳标题 + 构建最终发布 Payload
// ═══════════════════════════════════════════════════

const dsResponse = $input.first().json;
const prev = $('🔍 关键词提取 + 标题评分').first().json;
const seoTitles = dsResponse.choices?.[0]?.message?.content || '';

// 从 SEO 输出中提取第一个标题行
const firstTitleMatch = seoTitles.match(/^1\.\s*\*{0,2}(.+?)\*{0,2}\s*—/m);
let optimisedTitle = prev._original_title;
if (firstTitleMatch) {
  optimisedTitle = firstTitleMatch[1].trim();
}

function guessSubreddit(content) {
  const c = content.toLowerCase();
  if (c.includes('ap ') || c.includes('advanced placement')) return 'APExams';
  if (c.includes('a-level') || c.includes('alevel')) return 'ALevel';
  if (c.includes('ib ') || c.includes('international baccalaureate')) return 'IBDiploma';
  if (c.includes('sat') || c.includes('act')) return 'SATPrep';
  if (c.includes('牛剑') || c.includes('oxbridge')) return 'Oxbridge';
  if (c.includes('竞赛') || c.includes('olympiad') || c.includes('bpho')) return 'Competitions';
  if (c.includes('文书') || c.includes('personal statement')) return 'EssayWorkshop';
  return 'AcademicDaily';
}

// 添加 SEO meta description
const metaDesc = (prev._content || '').substring(0, 157).replace(/[#*\n]/g, ' ') + '...';

return {
  secret_key: $env.AI_WEBHOOK_SECRET,
  title: optimisedTitle,
  content: prev._content,
  subredditName: guessSubreddit(prev._content),
  authorRole: 'Midas',
  // SEO 元数据（不通过 API 发布，记录在日志中供分析）
  _seo_meta: {
    original_title: prev._original_title,
    optimised_title: optimisedTitle,
    keywords: prev._keywords,
    description: metaDesc,
    seo_raw: seoTitles
  }
};

const response = $input.first().json;
const seoData = $('📦 最佳标题 + Payload 构建').first().json;

return {
  status: 'published',
  post_id: response.id,
  subreddit: response.subredditName,
  url: `http://localhost:3000/r/${response.subredditName}/post/${response.id}`,
  seo_report: {
    original: seoData._seo_meta?.original_title,
    optimised: seoData._seo_meta?.optimised_title,
    keywords: seoData._seo_meta?.keywords
  },
  timestamp: new Date().toISOString()
};
